parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"leadQualityScore": {
			"type": "number",
			"description": "Lead quality score from 0-100"
		},
		"ageRange": {
			"type": "string",
			"description": "Estimated age range"
		},
		"incomeBracket": {
			"type": "string",
			"description": "Estimated income bracket"
		},
		"familyStatus": {
			"type": "string",
			"description": "Estimated family status"
		},
		"engagementLevel": {
			"type": "string",
			"description": "Engagement level: low, medium, high"
		},
		"purchaseIntent": {
			"type": "string",
			"description": "Purchase intent: browsing, considering, ready"
		},
		"urgency": {
			"type": "string",
			"description": "Urgency level: low, medium, high"
		},
		"bestFitAgentType": {
			"type": "string",
			"description": "Best-fit agent type"
		},
		"recommendedAction": {
			"type": "string",
			"description": "Recommended next action"
		}
	}
}
